mapper.select:
SELECT sal.id, sal.action, sal.target_id, sal.target_type, sal.value, sal.created_at, COALESCE(creator.username, 'Unknown') AS creator FROM sys_audit_log sal LEFT JOIN sys_user creator ON sal.created_by = creator.id
AND creator.username LIKE #{username} || '%'
AND sal.target_type = #{targetType}
${ew.customSqlSegment}
